INSERT INTO shared_courses (code, semester, data, ai_summary, status)
VALUES ('4ITCZV003', 'LS 2025/26', '{"code":"4ITCZV003","name":"Actuarial risk modeling","semester":"LS 2025/26","credits":3,"language":"angličtina","examType":"zkouška","group":"volitelny","lecturer":"Ing. Pavel Zimmermann, Ph.D.","allLecturers":["Ing. Pavel Zimmermann, Ph.D. (garant)"],"description":"Předmět je zaměřen na poskytnutí znalosti a dovednosti v oblasti modelování pojistně matematických rizik. Studenti se naučí identifikovat, měřit a řídit rizika v pojišťovacím sektoru pomocí různých statistických, matematických a pravděpodobnostních modelů. Důraz je kladen na aplikaci těchto modelů v praxi a na jejich využití při strategickém rozhodování. Obsah předmětu je vytvořen na základě sylabu Evropské aktuárské asociace (CORE SYLLABUS FOR ACTUARIAL TRAINING IN EUROPE)","learningOutcomes":["Po absolvování předmětu by studenti měli dosáhnout následujících výsledků: Studenti budou mít základní a pokročilou znalost o aktuárských rizicích, včetně jejich charakteristik, příčin, měření a řízení. Studenti budou schopni identifikovat a modelovat různé typy rizik v pojistném sektoru pomocí statistických, matematických a pravděpodobnostních metod. Studenti budou schopni hodnotit a měřit riziko. Studenti budou schopni aplikovat naučené aktuárské modely na konkrétní situace v pojišťovacím sektoru a interpretovat výsledky pro podporu rozhodování."],"weeklyTopics":[{"week":1,"topic":"Regulace solventnosti"},{"week":2,"topic":"Riziko rezerv"},{"week":3,"topic":"Riziko pojistného"},{"week":4,"topic":"Riziko životního pojištění"},{"week":5,"topic":"Riziko zdravotního pojištění"},{"week":6,"topic":"Interní modely"}],"workload":{"lectures":0,"seminars":0,"project":0,"testPrep":0,"examPrep":78,"total":78},"components":[{"name":"Závěrečný test","weight":50,"type":"exam","description":"","maxScore":null,"passingScore":null},{"name":"Závěrečná ústní zkouška","weight":50,"type":"exam","description":"","maxScore":null,"passingScore":null}],"gradingScale":[{"grade":"1","label":"Výborně","minPercent":90},{"grade":"2","label":"Velmi dobře","minPercent":75},{"grade":"3","label":"Dobře","minPercent":60},{"grade":"4","label":"Nedostatečně","minPercent":0}],"requirements":[],"literature":{"required":[],"recommended":["IOA, Alessandro Carrato MSc FIA, and Gráinne McGuire PhD FIAA. \"A Practitioner’s Introduction to Stochastic Reserving.\" (2016).Shapland, Mark R., and Jessica Leong. \"Bootstrap modeling: beyond the basics. Casualty Actuarial Society E-Forum, Fall 2010. 2010.Wuthrich, Mario V., Non-Life Insurance: Mathematics & Statistics. https://dx.doi.org/10.2139/ssrn.2319328","IOA, Alessandro Carrato MSc FIA, and Gráinne McGuire PhD FIAA. \"A Practitioner’s Introduction to Stochastic Reserving.\" (2016).","PDF výstup (PDF)Dokument RTF (RTF)"]},"schedule":[],"insisUrl":"https://insis.vse.cz/auth/katalog/syllabus.pl?zpet=/auth/katalog/index.pl?vzorek=4IT,Dohledat=Search,fakulta=31140,obdobi=381,jak=dle_jmena;predmet=214005;lang=cz","aiSummary":""}'::jsonb, '', 'validated')
