INSERT INTO shared_courses (code, semester, data, ai_summary, status)
VALUES ('4IT580', 'LS 2025/26', '{"code":"4IT580","name":"Agilní projekt vývoje webové aplikace","semester":"LS 2025/26","credits":8,"language":"čeština","examType":"zkouška","group":"volitelny","lecturer":"prof. Ing. Alena Buchalcevová, Ph.D.","allLecturers":["prof. Ing. Alena Buchalcevová, Ph.D. (garant)","Ing. Jan Černý (cvičící, zkoušející)","Marek Honzal (tutor)","Ing. Martin Kapal (cvičící, zkoušející)","Tomáš Klíma (tutor)","Tomáš Kříž (tutor)","Ing. Veronika Kuchynková (tutor)","Matyas Mihalka (tutor)","Marcel Puškarik (tutor)","Petr Vnenk (tutor)"],"description":"Cílem předmětu je umožnit studentům prakticky si vyzkoušet realizaci projektu vývoje moderní webové aplikace v agilně řízeném týmu. Předmět umožní studentům řešit reálné problémy, se kterými se při vývoji webové aplikace agilním způsobem setkají. Pro vývoj se využívají technologie ReactJS, Redux a NodeJS, pomocí kterých průběžně týmový projekt realizuje. \nVstupní předpoklady předmětu: student má základy HTML, CSS, SQL a objektově orientovaného programování, základní znalosti Javascriptu a agilního vývoje. \nJe doporučeno předchozí absolvování předmětů 4IT573 Základy Node.js, 4ME486 Design uživatelských rozhraní, 4IZ571  Vývoj pokročilých webových aplikací v PHP.\nPředmět pokrývá následující tematické okruhy oblasti vzdělávání Informatika: Programování, Softwarové inženýrství, Uživatelská rozhraní.","learningOutcomes":["Po úspěšném absolvování předmětu budou studenti schopni navrhovat vlastní webové projekty a budou vědět o všech aspektech, které je třeba zohlednit, aby jejich projekt mohl být úspěšný."],"weeklyTopics":[{"week":1,"topic":"Prezentace témat projektů, představení účastníků a sestavení týmů"},{"week":2,"topic":"Seznámení s nástroji pro realizaci projektu"},{"week":3,"topic":"Realizace projektu"},{"week":4,"topic":"Průběžné prezentace výsledků vývoje jednotlivých týmů"},{"week":5,"topic":"Prezentace finálního produktu a akceptace zadavatelem"}],"workload":{"lectures":0,"seminars":26,"project":130,"testPrep":0,"examPrep":0,"total":208},"components":[{"name":"Semestrální práce","weight":80,"type":"project","description":"","maxScore":null,"passingScore":null},{"name":"Prezentace / obhajoba","weight":20,"type":"other","description":"","maxScore":null,"passingScore":null}],"gradingScale":[{"grade":"1","label":"Výborně","minPercent":90},{"grade":"2","label":"Velmi dobře","minPercent":75},{"grade":"3","label":"Dobře","minPercent":60},{"grade":"4","label":"Nedostatečně","minPercent":0}],"requirements":["nutnost zisku 50 % bodů v posledním sprintu viz https://4it580","cz/o-kurzu/"],"literature":{"required":["MARTIN, Robert C. Agile software development : principles, patterns and practices. Upper Saddle River: Pearson Education, 2003. ISBN 0-13-597444-5.   ZAKAS, Nicholas C. JavaScript pro webové vývojáře. Brno: Computer Press, 2009. ISBN 978-80-251-2509-0.   THAU. Velký průvodce JavaScriptem : tvorba interaktivních webových stránek v praxi. Praha: Grada, 2009. ISBN 978-80-247-2211-5.   AMBLER, Scott W.; LINES, Mark. Disciplined agile delivery : a practitioner''s guide to agile software delivery in th","MARTIN, Robert C. Agile software development : principles, patterns and practices. Upper Saddle River: Pearson Education, 2003. ISBN 0-13-597444-5.","ZAKAS, Nicholas C. JavaScript pro webové vývojáře. Brno: Computer Press, 2009. ISBN 978-80-251-2509-0.","THAU. Velký průvodce JavaScriptem : tvorba interaktivních webových stránek v praxi. Praha: Grada, 2009. ISBN 978-80-247-2211-5.","AMBLER, Scott W.; LINES, Mark. Disciplined agile delivery : a practitioner''s guide to agile software delivery in the enterprise. Upper Saddle River: IBM Press, 2012. ISBN 978-0-13-281013-5.","ZS 2020/2021ZS 2021/2022ZS 2022/2023ZS 2023/2024ZS 2024/2025ZS 2025/2026","ZS 2020/2021ZS 2021/2022ZS 2022/2023ZS 2023/2024ZS 2024/2025ZS 2025/2026","PDF výstup (PDF)Dokument RTF (RTF)"],"recommended":[]},"schedule":[],"insisUrl":"https://insis.vse.cz/auth/katalog/syllabus.pl?zpet=/auth/kat